   218	        /// </summary>
   219	        private void ScrollBy(bool isNext)
   220	        {
   221	            if (_panels.Count == 0)
   222	                return;
   223	
   224	            var panel = isNext ? _panels[^1] : _panels[0];
   225	            var panelSize = GetPanelLength(panel);
   226	            var scrollAmount = Math.Max(_tabBarContentSize, panelSize); // minimum 1 tab scroll
   227	            if (!isNext)
   228	            {
   229	                scrollAmount = -scrollAmount;
   230	            }
   231	            var position = ScrollEdgeAdjust(_scrollPosition + scrollAmount, panelSize);
   232	            _scrollPosition = position;
   233	        }
