   235	        private void CenterScrollPositionAroundSelectedItem()
   236	        {
   237	            var activeIndex = _activePanelIndexState.Value;
   238	            if (activeIndex < 0)
   239	                return;
   240	            if (activeIndex + 1 == _panels.Count)
   241	            {
   242	                var lastPanel = _panels.Last();
   243	                ScrollToItem(lastPanel, true);
   244	                return;
   245	            }
   246	
   247	            // scroll to the panel
   248	            ScrollToItem(ActivePanel!);
   249	        }
