   251	        private void SetScrollabilityStates()
   252	        {
   253	            var isEnoughSpace = _allTabsSize <= _tabBarContentSize;
   254	
   255	            if (isEnoughSpace)
   256	            {
   257	                _nextButtonDisabled = true;
   258	                _prevButtonDisabled = Math.Abs(_scrollPosition) < 0.01;
   259	            }
   260	            else
   261	            {
   262	                // Disable next button if the last panel is completely visible
   263	                _nextButtonDisabled = Math.Abs(_scrollPosition) >= GetLengthOfPanelItems(_panels[^1], true) - _tabBarContentSize;
   264	                _prevButtonDisabled = Math.Abs(_scrollPosition) < 0.01;
