   270	        internal async Task ItemUpdated(MudItemDropInfo<MudTabPanel> dropItem)
   271	        {
   272	            if (dropItem.Item is null)
   273	            {
   274	                return;
   275	            }
   276	
   277	            // get the old index where this item was at
   278	            var oldIndex = _panels.IndexOf(dropItem.Item);
   279	            // get the new index in _panels using IndexInZone
   280	            var newIndex = dropItem.IndexInZone;
   281	
   282	            // remove the item from the old index
   283	            _panels.RemoveAt(oldIndex);
   284	
   285	            // insert the item at the new index
   286	            if (newIndex < _panels.Count)
   287	            {
   288	                _panels.Insert(newIndex, dropItem.Item);
   289	            }
   290	            else
   291	            {
   292	                _panels.Add(dropItem.Item);
   293	            }
   294	
   295	            // Set the dragged tab as active
   296	            await ActivatePanelAsync(dropItem.Item);
   297	
   298	            if (OnItemDropped.HasDelegate)
   299	            {
   300	                await OnItemDropped.InvokeAsync(dropItem);
   301	            }
   302	        }
