   304	        /// <summary>
   305	        /// Handles keyboard navigation for tabs according to W3C accessibility guidelines
   306	        /// Supports Enter/Space for activation and arrow keys for navigation
   307	        /// </summary>
   308	        protected virtual async Task HandleTabKeyDownAsync(KeyboardEventArgs e, MudTabPanel panel)
   309	        {
   310	            switch (e.Key)
   311	            {
   312	                case "Enter":
   313	                case " ":
   314	                    // considered a click
   315	                    var args = new MouseEventArgs() { Type = e.Key, Detail = 1, ClientX = 0, ClientY = 0 };
   316	                    await ActivatePanelClickAsync(panel, args);
   317	                    break;
   318	
   319	                case "ArrowLeft":
   320	                    if (!_isVerticalTabs)
   321	                    {
   322	                        await MoveFocusToPreviousTab(panel);
   323	                    }
   324	                    break;
   325	
   326	                case "ArrowRight":
   327	                    if (!_isVerticalTabs)
   328	                    {
   329	                        await MoveFocusToNextTab(panel);
   330	                    }
   331	                    break;
   332	
   333	                case "ArrowUp":
   334	                    if (_isVerticalTabs)
   335	                    {
   336	                        await MoveFocusToPreviousTab(panel);
   337	                    }
   338	                    break;
   339	
   340	                case "ArrowDown":
   341	                    if (_isVerticalTabs)
   342	                    {
   343	                        await MoveFocusToNextTab(panel);
   344	                    }
   345	                    break;
   346	            }
   347	        }
