   358	        /// <summary>
   359	        /// Allows the user to move to the previous tab using key arrow
   360	        /// </summary>
   361	        private async Task MoveFocusToPreviousTab(MudTabPanel currentPanel)
   362	        {
   363	            var enabledPanels = _panels.Where(p => !p.Disabled).ToList();
   364	            if (enabledPanels.Count <= 1) return;
   365	
   366	            var currentIndex = enabledPanels.IndexOf(currentPanel);
   367	            var previousIndex = currentIndex <= 0 ? enabledPanels.Count - 1 : currentIndex - 1;
   368	            var previousPanel = enabledPanels[previousIndex];
   369	
   370	            await FocusPanel(previousPanel);
   371	        }
