   373	        /// <summary>
   374	        /// Allows the user to move to the next tab using KeyArrow
   375	        /// </summary>
   376	        private async Task MoveFocusToNextTab(MudTabPanel currentPanel)
   377	        {
   378	            var enabledPanels = _panels.Where(p => !p.Disabled).ToList();
   379	            if (enabledPanels.Count <= 1) return;
   380	
   381	            var currentIndex = enabledPanels.IndexOf(currentPanel);
   382	            var nextIndex = currentIndex >= enabledPanels.Count - 1 ? 0 : currentIndex + 1;
   383	            var nextPanel = enabledPanels[nextIndex];
   384	
   385	            await FocusPanel(nextPanel);
   386	        }
