   107	    private RenderFragment RenderTab(MudTabPanel panel) =>
   108	        @<div @ref="panel.PanelRef" class="@GetTabClass(panel)" style="@GetTabStyle(panel)" @onclick="@(e => ActivatePanelClickAsync(panel, e, false))" @onmousedown="panel.OnMouseDown" @oncontextmenu="panel.OnContextMenu" @oncontextmenu:preventDefault="@(panel.OnContextMenu.HasDelegate)"
   109	              aria-controls="@GetTabPanelId(panel)" role="tab" id="@GetTabId(panel)" aria-selected="@(panel == ActivePanel ? "true" : "false")"
   110	              tabindex="@(panel == ActivePanel ? "0" : "-1")" @onkeydown="@(e => HandleTabKeyDownAsync(e, panel))">
   111	            @if (TabPanelHeaderPosition == TabHeaderPosition.Before && TabPanelHeader is not null)
   112	            {
   113	                <div class="mud-tabs-panel-header mud-tabs-panel-header-before">
   114	                    @TabPanelHeader(panel)
   115	                </div>
   116	            }
   117	            @if (panel.TabContent is not null)
   118	            {
   119	                @panel.TabContent
   120	            }
   121	            else if (!string.IsNullOrEmpty(panel.Text) && string.IsNullOrEmpty(panel.Icon))
   122	            {
   123	                @panel.Text
   124	            }
   125	            else if (string.IsNullOrEmpty(panel.Text) && !string.IsNullOrEmpty(panel.Icon))
   126	            {
   127	                <MudIcon Icon="@panel.Icon" Color="@GetPanelIconColor(panel)" />
   128	            }
