                .AddClass($"mud-tabs-vertical", _isVerticalTabs)
                .AddClass($"mud-tabs-vertical-reverse", (Position == Position.Right && !RightToLeft) || ((Position == Position.Left) && RightToLeft) || Position == Position.End)
                .AddClass(InternalClassName)
                .AddClass(Class)
                .Build();

